    question: "Demonstrate interface with events.",
    mathSolution: "Interfaces can declare events.",
    codeSolution: "using System;\n\ninterface IButton\n{\n    event EventHandler Clicked;\n    void Click();\n}\n\nclass SubmitButton : IButton\n{\n    public event EventHandler Clicked;\n    \n    public void Click()\n    {\n        Console.WriteLine(\"Submit button clicked\");\n        Clicked?.Invoke(this, EventArgs.Empty);\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        IButton button = new SubmitButton();\n        button.Clicked += (sender, e) => Console.WriteLine(\"Button clicked event handled\");\n        button.Click();\n    }\n}",
    hint: "Events in interfaces are implemented as events in classes.",
