    codeSolution: "using System;\n\npublic delegate void NotifyDelegate(string message);\n\nclass Program\n{\n    static void Main()\n    {\n        NotifyDelegate notify = Console.WriteLine;\n        notify += SendEmail;\n        notify += LogToFile;\n        \n        notify(\"System notification\");\n        \n        Console.WriteLine(\"\\nRemoving Email delegate...\");\n        notify -= SendEmail;\n        notify(\"Second notification\");\n    }\n    \n    static void SendEmail(string message)\n    {\n        Console.WriteLine($\"[EMAIL] Sending: {message}\");\n    }\n    \n    static void LogToFile(string message)\n    {\n        Console.WriteLine($\"[LOG] Writing: {message}\");\n    }\n}",
