    codeSolution: "using System;\n\npublic delegate void ProcessDelegate(int value);\n\nclass Program\n{\n    static void Main()\n    {\n        ProcessData(10, DoubleValue);\n        ProcessData(5, SquareValue);\n        ProcessData(7, value => Console.WriteLine($\"Lambda: {value * 3}\"));\n    }\n    \n    static void ProcessData(int data, ProcessDelegate processor)\n    {\n        Console.Write($\"Processing {data}: \");\n        processor(data);\n    }\n    \n    static void DoubleValue(int x)\n    {\n        Console.WriteLine($\"Double = {x * 2}\");\n    }\n    \n    static void SquareValue(int x)\n    {\n        Console.WriteLine($\"Square = {x * x}\");\n    }\n}",
