    id: "cs_delegates_5",
    topicId: "cs_delegates",
    question: "Use Func<T, TResult> built-in delegate for methods with return value.",
    mathSolution: "Func delegate for methods returning values.",
    codeSolution: "using System;\n\nclass Program\n{\n    static void Main()\n    {\n        // Func with 1 parameter, 1 return\n        Func<int, int> square = x => x * x;\n        Console.WriteLine($\"Square of 5: {square(5)}\");\n        \n        // Func with 2 parameters, 1 return\n        Func<int, int, int> add = (a, b) => a + b;\n        Console.WriteLine($\"Sum: {add(10, 20)}\");\n        \n        // Func with 3 parameters, 1 return\n        Func<int, int, int, int> multiply = (a, b, c) => a * b * c;\n        Console.WriteLine($\"Product: {multiply(2, 3, 4)}\");\n        \n        // Func with string parameter, bool return\n        Func<string, bool> isValidEmail = email => email.Contains(\"@\") && email.Contains(\".\");\n        Console.WriteLine($\"Is valid email? {isValidEmail(\"test@example.com\")}\");\n        \n        // Func with complex logic\n        Func<double, double, double> calculateBMI = (weight, height) => weight / (height * height);\n        double bmi = calculateBMI(70, 1.75);\n        Console.WriteLine($\"BMI: {bmi:F2}\");\n    }\n}",
    hint: "Func delegates are predefined for methods with return values (up to 16 parameters).",
