    id: "cs_delegates_7",
    topicId: "cs_delegates",
    question: "Create delegate with anonymous method.",
    mathSolution: "Anonymous methods using delegate keyword.",
    codeSolution: "using System;\n\nclass Program\n{\n    static void Main()\n    {\n        // Anonymous method with delegate keyword\n        Func<int, int, int> add = delegate(int a, int b)\n        {\n            return a + b;\n        };\n        Console.WriteLine($\"Anonymous method sum: {add(5, 3)}\");\n        \n        // Anonymous method as event handler\n        Action<string> logger = delegate(string msg)\n        {\n            Console.WriteLine($\"[LOG] {DateTime.Now:T}: {msg}\");\n        };\n        logger(\"Application started\");\n        \n        // Anonymous method with complex logic\n        Func<double, double, double> calculate = delegate(double radius, double height)\n        {\n            double area = Math.PI * radius * radius;\n            double volume = area * height;\n            return volume;\n        };\n        double cylinderVolume = calculate(5, 10);\n        Console.WriteLine($\"Cylinder volume: {cylinderVolume:F2}\");\n        \n        // Anonymous method capturing outer variable\n        int multiplier = 3;\n        Func<int, int> times = delegate(int x)\n        {\n            return x * multiplier; // Captures multiplier\n        };\n        Console.WriteLine($\"10 * 3 = {times(10)}\");\n    }\n}",
