    topicId: "cs_delegates",
    question: "Create delegate with ref and out parameters.",
    mathSolution: "Delegates with reference and output parameters.",
    codeSolution: "using System;\n\n// Delegate with ref and out parameters\npublic delegate void Calculator(int a, int b, ref int sum, out int product);\n\nclass Program\n{\n    static void Main()\n    {\n        Calculator calc = Calculate;\n        \n        int sum = 0;\n        int product;\n        \n        calc(10, 20, ref sum, out product);\n        \n        Console.WriteLine($\"Sum: {sum}\");\n        Console.WriteLine($\"Product: {product}\");\n        \n        // Delegate with ref parameter only\n        Action<int, ref int> addTo = (value, ref total) => total += value;\n        \n        int total = 5;\n        addTo(10, ref total);\n        Console.WriteLine($\"\\nTotal after adding: {total}\");\n        \n        // Delegate with out parameter only\n        Func<int, int, out int> divide = (a, b, out int result) =>\n        {\n            if (b == 0)\n            {\n                result = 0;\n                return false;\n            }\n            result = a / b;\n            return true;\n        };\n        \n        int quotient;\n        bool success = divide(20, 4, out quotient);\n        Console.WriteLine($\"Division result: {quotient}, Success: {success}\");\n        \n        // Multiple out parameters\n        Action<string, out int, out bool> parse = (input, out int num, out bool isNumber) =>\n        {\n            isNumber = int.TryParse(input, out num);\n        };\n        \n        parse(\"123\", out int number, out bool ok);\n        Console.WriteLine($\"\\nParsed '{123}': {number}, Valid: {ok}\");\n    }\n    \n    static void Calculate(int a, int b, ref int sum, out int product)\n    {\n        sum = a + b;\n        product = a * b;\n    }\n}",
    hint: "Delegates can have ref and out parameters like regular methods.",
