    mathSolution: "Cancelable events using CancelEventArgs.",
    codeSolution: "using System;\nusing System.ComponentModel;\n\nclass Form\n{\n    public event EventHandler<CancelEventArgs> Closing;\n    \n    public void Close()\n    {\n        var args = new CancelEventArgs();\n        Closing?.Invoke(this, args);\n        \n        if (args.Cancel)\n        {\n            Console.WriteLine(\"Form closing was cancelled\");\n        }\n        else\n        {\n            Console.WriteLine(\"Form closed\");\n        }\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        var form = new Form();\n        \n        // Event handler that can cancel\n        form.Closing += (sender, e) =>\n        {\n            Console.WriteLine(\"Save changes? (y/n)\");\n            string input = Console.ReadLine();\n            if (input?.ToLower() != \"y\")\n            {\n                e.Cancel = true;\n                Console.WriteLine(\"Close cancelled - changes not saved\");\n            }\n        };\n        \n        form.Close();\n        form.Close();\n    }\n}",
    hint: "Use CancelEventArgs to allow event handlers to cancel operations.",
